import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import Thumbnail from './Thumbnail';
import { useId } from '@andes/context';
import includes from '@andes/common/build/utils/includes';
import { AVAILABLE_TYPES, TYPE_GRID, TYPE_STACKED } from '../constants/types';
import {
  STACKED_SIZES,
  GRID_SIZES,
  SIZE_80,
  SIZE_72,
  SIZE_48,
  SIZE_40,
  SIZE_32,
  SIZE_24,
  SIZE_16,
} from '../constants/sizes';
import { useThemeContext } from '@andes/themes';

const namespace = 'andes-thumbnail-multiple';

/** @typedef {import('../../index').ThumbnailType} Type */
/** @typedef {Exclude<import('../../index').ThumbnailSize, '96'>} Size */

/**
 * @param {Type} type
 * @param {Size} containerSize
 * @return {Size}
 */
const getChildrenSize = (type, containerSize) => {
  /** @type {Size} */
  let childrenSize;

  const isLargeContainer = containerSize === SIZE_72 || containerSize === SIZE_80;
  const isSmallContainer = containerSize === SIZE_40 || containerSize === SIZE_48;

  if (type === TYPE_GRID) {
    if (isLargeContainer) {
      childrenSize = SIZE_32;
    } else if (isSmallContainer) {
      childrenSize = SIZE_16;
    } else {
      childrenSize = SIZE_24;
    }
  } else {
    childrenSize = containerSize;
  }

  return childrenSize;
};

/** @type {import('prop-types').Validator<React.ReactElement>} */
const checkCount = ({ children }, propName, componentName) => {
  PropTypes.checkPropTypes({ children: PropTypes.element.isRequired }, { children }, propName, componentName);

  const childrenQuantity = React.Children.count(children);
  if (childrenQuantity < 2 || childrenQuantity > 4) {
    return new Error(
      'Thumbnail Multiple is meant for 2, 3 or 4 thumbnails. Please use the appropiate amount of children',
    );
  }

  return null;
};

/** @type {import('prop-types').Validator<Type>} */
const checkThumbnailType = ({ type, containerSize }, propName, componentName) => {
  PropTypes.checkPropTypes({ type: PropTypes.oneOf(AVAILABLE_TYPES) }, { type }, propName, componentName);

  if (type === TYPE_GRID && !includes(GRID_SIZES, containerSize)) {
    return new Error(`Grid type only accepts sizes '40', '48', '56', '64', '72', 80'.
    Please select one of these options`);
  } if (type === TYPE_STACKED && !includes(STACKED_SIZES, containerSize)) {
    return new Error(`Stacked type only accepts sizes '24', '32', '40', '48', '56', '64', '72', '80'.
    Please select one of these options`);
  }

  return null;
};

/** @type {typeof import('../../index').ThumbnailMultiple} */
const ThumbnailMultiple = ({
  children,
  className,
  containerSize = '56',
  id,
  modifier = 'circle',
  overflow,
  type = 'grid',
  ref,
}) => {
  const componentId = useId(id);
  const { getThemedComponentClasses, themeHash } = useThemeContext();

  const classes = classNames(
    namespace,
    `${namespace}--${type}`,
    `${namespace}--${type}-${containerSize}`,
    className,
    getThemedComponentClasses?.('thumbnail'),
  );

  const childSize = getChildrenSize(type, containerSize);

  return (
    <div
      className={classes}
      ref={ref}
      data-andes-thumbnail-multiple
      data-andes-thumbnail-multiple-type={type}
      {...themeHash}
    >
      {
        React.Children.map(children,
          ((/** @type {React.ReactElement} */ child, index) => React.cloneElement(child, {
            size: childSize,
            modifier,
            id: child.props.id || `${componentId}-${index}`,
          })))
      }
      {overflow && (
        <Thumbnail
          id={`${componentId}-overflow`}
          className={`${namespace}--overflow`}
          size={childSize}
          modifier={modifier}
          andesDataAttributes={{ 'data-andes-thumbnail-multiple-overflow': true }}
        >
          <span>+{overflow}</span>
        </Thumbnail>
      )}
    </div>
  );
};

ThumbnailMultiple.propTypes = {
  children: checkCount,
  className: PropTypes.string,
  containerSize: PropTypes.oneOf(['24', '32', '40', '48', '56', '64', '72', '80']),
  id: PropTypes.string,
  modifier: PropTypes.oneOf(['circle', 'square']),
  overflow: PropTypes.number,
  type: checkThumbnailType,
};

ThumbnailMultiple.displayName = 'ThumbnailMultiple';

export default ThumbnailMultiple;
