const DEPRECATED_COLOR_GREEN = /** @type {const} */('green');
const DEPRECATED_COLOR_RED = /** @type {const} */('red');
const DEPRECATED_COLOR_ORANGE = /** @type {const} */('orange');

const COLOR_POSITIVE = /** @type {const} */('positive');
const COLOR_CAUTION = /** @type {const} */('caution');
const COLOR_NEGATIVE = /** @type {const} */('negative');

const ALLOWED_COLORS = /** @type {const} */([
  COLOR_POSITIVE,
  COLOR_CAUTION,
  COLOR_NEGATIVE,
]);

const DEPRECATED_COLORS = /** @type {const} */([
  DEPRECATED_COLOR_GREEN,
  DEPRECATED_COLOR_RED,
  DEPRECATED_COLOR_ORANGE,
]);

const ALL_COLORS = /** @type {const} */([
  ...ALLOWED_COLORS,
  ...DEPRECATED_COLORS,
]);

export {
  DEPRECATED_COLOR_GREEN,
  DEPRECATED_COLOR_RED,
  DEPRECATED_COLOR_ORANGE,
  COLOR_POSITIVE,
  COLOR_CAUTION,
  COLOR_NEGATIVE,
  ALLOWED_COLORS,
  DEPRECATED_COLORS,
  ALL_COLORS,
};
