import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import { useAndesContext, useId } from '@andes/context';
import Close16 from '@andes/icons/Close16';
import { VisuallyHidden } from '@andes/visually-hidden';
import { computeDataAndesState } from '@andes/common/build/utils/computeDataAndesState';
import includes from '@andes/common/build/utils/includes';
import warning from '@andes/common/build/utils/warning';
import { DEPRECATED_COLOR_WARNINGS } from './constants/warning';
import { namespace } from './constants';
import { ALLOWED_COLORS, DEPRECATED_COLORS } from './constants/colors';
import ThumbnailAsset from './components/ThumbnailAsset';
import TagIcon from './components/TagIcon';
import computeColor from './utils/computeColors';
import { useThemeContext } from '@andes/themes';
import enTranslations from '../translations/en/messages.json';
import zhCnTranslations from '../translations/zh-CN/messages.json';
import esArTranslations from '../translations/es-AR/messages.json';
import ptBrTranslations from '../translations/pt-BR/messages.json';

/** @typedef {import('../index').Color} Color */

/** @typedef {import('../index').DeprecatedColors} DeprecatedColors */

/** @typedef {React.ComponentProps<typeof import('../index').Tag>} TagPublicProps */

/**
 * @typedef {Object} TagInternalProps
 * @prop {Record<string, unknown>} [andesDataAttributes]
 * @prop {string} [ariaLive]
 */

/**
 * @param {Color} [color]
 * @return {Record<string, unknown> | undefined}
 */
const getContainerCustomColorStyle = (color) => {
  if (!color) return;

  const {
    backgroundColor,
    borderColor,
    color: textColor,
    closeIconColorHover,
    closeIconColorActive,
  } = color;

  return {
    style: {
      '--andes-tag-color-text-default': textColor,
      '--andes-tag-color-fill-default': backgroundColor,
      '--andes-tag-color-border-default': borderColor,
      '--andes-tag-color-close-default': textColor,
      '--andes-tag-color-close-hover': closeIconColorHover,
      '--andes-tag-color-close-active': closeIconColorActive,
      '--andes-tag-color-icon-default': textColor,
    },
  };
};

/**
 *
 * @param {Color | "positive" | "caution" | "negative" | DeprecatedColors} [color]
 */
const getColor = (color) => ({
  customColor: typeof color === 'object' ? color : undefined,
  computedColor: color && typeof color === 'string' ? computeColor(color) : undefined,
});

/** @type {React.FunctionComponent<TagPublicProps & TagInternalProps>} */
const Tag = ({
  andesDataAttributes,
  'aria-live': ariaLive,
  asset,
  icon,
  children,
  className,
  clickable = false,
  closeButtonSrLabel,
  color,
  component,
  disabled = false,
  id,
  label,
  onClick,
  onClose,
  size = 'large',
  srLabel,
  ref,
}) => {
  const componentId = useId(id);

  const { i18n } = useAndesContext(
    '@andes/tag',
    { en: enTranslations, 'es-AR': esArTranslations, 'pt-BR': ptBrTranslations, 'zh-CN': zhCnTranslations },
  );

  const { getThemedComponentClasses, themeHash } = useThemeContext();

  const { customColor, computedColor } = getColor(color);

  // @deprecate [color] options: ['accent', 'green', 'orange', 'red'] - Warning from: 9.0.0
  if (typeof color === 'string') {
    warning(
      !includes(DEPRECATED_COLORS, color),
      DEPRECATED_COLOR_WARNINGS[/** @type {keyof DEPRECATED_COLOR_WARNINGS} */ (color)],
    );
  }

  /** @param {React.MouseEvent<HTMLButtonElement>} event */
  const handleClose = (event) => {
    event.stopPropagation();
    if (!disabled && typeof onClose === 'function') onClose(event);
  };

  const getClose = () => (
    <button
      type="button"
      className={`${namespace}__close`}
      onClick={handleClose}
      disabled={disabled}
      aria-label={closeButtonSrLabel || i18n.pgettext(namespace, 'quitar {0}', label)}
      data-andes-tag-close
    >
      <span aria-hidden className={`${namespace}__icon-container`}>
        <Close16 color="currentColor" />
      </span>
    </button>
  );

  const tagClassName = classNames(namespace, className, {
    [`${namespace}--${size}`]: size,
    [`${namespace}__color--${computedColor}`]: computedColor,
    [`${namespace}--disabled`]: disabled,
    [`${namespace}--clickable`]: (typeof onClick === 'function' || clickable) && !disabled,
    [`${namespace}--custom-color`]: customColor,
  },
  getThemedComponentClasses?.('tag'),
  );

  const messageDisabled = () => (
    disabled && (
      <VisuallyHidden>
        {i18n.pgettext(namespace, 'deshabilitado')}:
      </VisuallyHidden>
    )
  );

  const screenReaderLabel = () => (
    srLabel && <VisuallyHidden>{srLabel}</VisuallyHidden>
  );

  const content = children
    ? (
      <div className={`${namespace}__child`}>
        {messageDisabled()}
        {screenReaderLabel()}
        {children}
      </div>
    )
    : (
      <div className={`${namespace}__label`}>
        {messageDisabled()}
        {screenReaderLabel()}
        {label}
      </div>
    );

  let tagProps;
  let /** @type {React.ElementType} */ Component;

  if (typeof onClick === 'function' && !disabled) {
    tagProps = {
      className: tagClassName,
      onClick,
      type: 'button',
    };
    Component = component || 'button';
  } else {
    tagProps = { className: tagClassName };
    Component = component || 'div';
  }

  return (
    // 'Component' onClick event type does not match types with div event type
    <Component
      {...tagProps}
      {...themeHash}
      {...andesDataAttributes}
      ref={ref}
      id={componentId}
      aria-live={ariaLive}
      data-andes-tag
      data-andes-tag-type="simple"
      data-andes-tag-size={size}
      data-andes-tag-color={computedColor}
      {...computeDataAndesState({ disabled })}
      {...getContainerCustomColorStyle(customColor)}
    >
      <>
        {asset && size === 'large' && (
          <ThumbnailAsset {...asset} color={asset?.color} imageAlt={label} />
        )}
        {icon && size === 'large' && <TagIcon icon={icon} />}
        {content}
        {typeof onClose === 'function' && getClose()}
      </>
    </Component>
  );
};

Tag.displayName = 'Tag';

Tag.propTypes = {
  andesDataAttributes: PropTypes.shape({}),
  asset: PropTypes.shape({
    icon: PropTypes.element,
    imageUrl: PropTypes.string,
    text: PropTypes.string,
    color: PropTypes.shape({
      backgroundColor: PropTypes.string,
      borderColor: PropTypes.string,
      color: PropTypes.string,
    }),
  }),
  icon: PropTypes.element,
  children: PropTypes.node,
  className: PropTypes.string,
  clickable: PropTypes.bool,
  closeButtonSrLabel: PropTypes.string,
  color: PropTypes.oneOf([ALLOWED_COLORS, PropTypes.shape({
    backgroundColor: PropTypes.string,
    borderColor: PropTypes.string,
    color: PropTypes.string,
    closeIconColorHover: PropTypes.string,
    closeIconColorActive: PropTypes.string,
  })]),
  component: PropTypes.elementType,
  disabled: PropTypes.bool,
  id: PropTypes.string,
  label: PropTypes.string.isRequired,
  onClick: PropTypes.func,
  onClose: PropTypes.func,
  size: PropTypes.oneOf(['small', 'large']),
  srLabel: PropTypes.string,
};

export default Tag;
