import React, { isValidElement } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import warning from '@andes/common/build/utils/warning';
import includes from '@andes/common/build/utils/includes';
import { useId } from '@andes/context';
import { VisuallyHidden } from '@andes/visually-hidden';
import { namespace } from '../constants';
import { WARNING_HIERARCHY_DEPRECATED } from '../constants/warnings';
import { useThemeContext } from '@andes/themes';

const allowedBadgeTypes = ['Dot', 'Pill'];

/** @typedef {import('../../index').ThumbnailSize} Size */
/** @typedef {import('../../index').Color} Color */
/** @typedef {import('../../index').ThumbnailHierarchy} Hierarchy */

/**
 * @param {Size} size
 * @return {'large' | 'small'}
 */
const getBadgeSizeByThumbnailSize = (size) => {
  if (size === '80' || size === '72' || size === '64') return 'large';
  return 'small';
};

/**
 * @param {React.ReactElement} children
 * @return {boolean}
 */
function isIcon(children) {
  if (isValidElement(children) && typeof children.type === 'function') {
    // @ts-expect-error - The type of children.type is callable, was previously checked with typeof
    return children.type(children.props).type === 'svg';
  }

  return false;
}

/**
 * @param {React.ReactElement} children
 * @return {boolean}
 */
const isImage = (children) => {
  if (isValidElement(children)) {
    return children.type === 'img' || children.props.src;
  }

  return false;
};

/**
 * @param {React.ReactElement} children
 * @return {boolean}
 */
function isText(children) {
  if (isValidElement(children)) {
    return !children.props.src && !isIcon(children);
  }

  return false;
}

/**
 * @param {Size} size
 * @param {React.ReactElement} badge
 * @return {React.ReactElement | boolean}
 */
const verifyBadgeType = (size, badge) => {
  // @ts-expect-error: we add displayName
  const isDot = badge.type.displayName === 'Dot';

  if ((isDot && (size === '24' || size === '32'))
      || (!isDot && (size !== '24' && size !== '32'))) {
    return badge;
  }

  warning(!isDot, `${size} should use Pill Badges`);

  return false;
};

/**
 * @param {Color | undefined} color
 * @param {Hierarchy} hierarchy
 * @return {Record<string, unknown> | undefined}
 */
const getContainerCustomColorStyle = (color, hierarchy) => {
  if (!color) return;

  const { backgroundColor, borderColor, color: textColor } = color;

  return {
    style: {
      [`--andes-thumbnail-${hierarchy}-color-text-default`]: textColor,
      [`--andes-thumbnail-${hierarchy}-color-fill-default`]: backgroundColor,
      '--andes-thumbnail-color-border-default': borderColor,
      '--andes-color-icon-primary': textColor,
    },
  };
};

/**
 * @typedef {Object} ThumbnailInternalProps
 * @prop {Record<string, unknown>} [andesDataAttributes]
 */

/** @typedef {import('../../index').ThumbnailProps} ThumbnailPublicProps */

/** @typedef {ThumbnailInternalProps & ThumbnailPublicProps} ThumbnailProps */

/** @type {React.FunctionComponent<ThumbnailProps>} */
const Thumbnail = ({
  badge,
  children,
  className,
  color: customColor,
  disabled = false,
  hierarchy = 'mute',
  id,
  modifier = 'circle',
  size = '48',
  srLabel,
  ref,
  backgroundType,
  andesDataAttributes = {},
}) => {
  const { getThemedComponentClasses, themeHash } = useThemeContext();
  const componentId = useId(id);

  // @deprecate [hierarchy="neutral"] - Warning from: 9.0.0
  if (typeof hierarchy === 'string') {
    warning(hierarchy !== 'neutral', WARNING_HIERARCHY_DEPRECATED);
  }

  const badgeColor = badge ? badge.props?.color || 'accent' : undefined;
  const computedHierarchy = badge ? 'mute' : hierarchy;

  const classes = classNames(
    namespace,
    `${namespace}--${modifier}`,
    `${namespace}--${size}`,
    {
      [`${namespace}__badge`]: badge,
      [`${namespace}__badge-${badgeColor}`]: badgeColor,
      [`${namespace}__image`]: isImage(children),
      [`${namespace}__image--disabled`]: isImage(children) && disabled,
      [`${namespace}__icon`]: isIcon(children),
      [`${namespace}--${computedHierarchy}`]: (isIcon(children) || isText(children)),
      [`${namespace}--${computedHierarchy}-disabled`]: (isIcon(children) || isText(children)) && disabled,
    },
    className);

  const wrapperClasses = classNames(
    `${namespace}-container`,
    {
      [`${namespace}--color-on-background`]: backgroundType === 'complexBackground',
    },
    getThemedComponentClasses?.('thumbnail'),
  );

  const a11yProps = {
    ...(!isImage(children) && { 'aria-hidden': !!srLabel }),
    title: srLabel,
  };

  const getColor = () => {
    // @ts-expect-error - It is previously verified that it is an SVG which can contain the color prop.
    const color = children.props?.color;

    return { color: color !== 'rgba(0, 0, 0, 0.9)'
      ? color
      : 'currentColor' };
  };

  const sharedProps = {
    ...themeHash,
    ...andesDataAttributes,
    'data-andes-thumbnail': true,
    'data-andes-thumbnail-hierarchy': computedHierarchy,
    'data-andes-thumbnail-size': size,
  };

  return (
    <div className={wrapperClasses} ref={ref} {...sharedProps}>
      <div className={classes} data-andes-thumbnail-content {...getContainerCustomColorStyle(customColor, computedHierarchy)}>
        {
          React.Children.only(
            isIcon(children)
              ? React.cloneElement(children, { ...getColor(), ...a11yProps })
              : React.cloneElement(children, { ...a11yProps }),
          )
        }
        {srLabel && <VisuallyHidden>{srLabel}</VisuallyHidden>}
      </div>
      {badge && verifyBadgeType(size, badge) && React.cloneElement(badge,
        {
          size: getBadgeSizeByThumbnailSize(size),
          id: badge.props.id || `${componentId}-thumbnail-badge`,
          backgroundType,
        })}
    </div>
  );
};

/** @type {import('prop-types').Validator<React.ReactElement>} */
const checkBadgeType = ({ badge }, propName, componentName) => {
  PropTypes.checkPropTypes({ badge: PropTypes.element }, { badge }, propName, componentName);

  const badgeType = badge?.type?.displayName;
  if (!badgeType) return null;

  if (!includes(allowedBadgeTypes, badgeType)) {
    throw new TypeError(`${badgeType} is not allowed`);
  }

  return null;
};

/** @type {import('prop-types').Validator<Size>} */
const checkThumbnailSize = ({ size, children, badge }, propName, componentName) => {
  PropTypes.checkPropTypes(
    { size: PropTypes.oneOf(['96', '80', '72', '64', '56', '48', '40', '32', '24', '16']) },
    { size },
    propName,
    componentName,
  );

  if (size === '16' && isIcon(children)) {
    return new Error(
      'Thumbnail of size 16px can\'t be used with icon.',
    );
  }

  if (size === '16' && typeof badge !== 'undefined') {
    return new Error(
      'Thumbnail of size 16px can\'t be used with badge.',
    );
  }

  return null;
};

Thumbnail.displayName = 'Thumbnail';

Thumbnail.propTypes = {
  badge: checkBadgeType,
  children: PropTypes.element.isRequired,
  className: PropTypes.string,
  color: PropTypes.shape({
    backgroundColor: PropTypes.string,
    borderColor: PropTypes.string,
    color: PropTypes.string,
  }),
  disabled: PropTypes.bool,
  hierarchy: PropTypes.oneOf([
    'loud',
    'quiet',
    'mute',
  ]),
  id: PropTypes.string,
  modifier: PropTypes.oneOf([
    'circle',
    'square',
  ]),
  size: checkThumbnailSize,
  srLabel: PropTypes.string,
  backgroundType: PropTypes.oneOf(['default', 'complexBackground']),
  andesDataAttributes: PropTypes.shape({}),
};

export default Thumbnail;
